import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';
import { optionLabelByValue, useParcelOptions, usePersonOptions } from 'features/shared/selectOptionHelpers';

export default function VehiclesPage() {
  const parcelOptions = useParcelOptions();
  const personOptions = usePersonOptions();

  return (
    <CrudResourceModule
      title="Vehículos"
      path={API_PATHS.vehicles}
      columns={[
        { key: 'ppu', label: 'PPU/Patente' },
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'marca', label: 'Marca' },
        { key: 'modelo', label: 'Modelo' },
        { key: 'color', label: 'Color' },
        {
          key: 'activo',
          label: 'Estado',
          render: (row) => <Chip size="small" label={row.activo ? 'Activo' : 'Inactivo'} color={row.activo ? 'success' : 'default'} />
        }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        { name: 'persona_id', label: 'Persona asociada', type: 'select', options: personOptions },
        { name: 'ppu', label: 'PPU/Patente', required: true },
        { name: 'marca', label: 'Marca' },
        { name: 'modelo', label: 'Modelo' },
        { name: 'tipo', label: 'Tipo vehículo' },
        { name: 'color', label: 'Color' },
        { name: 'codigo_acceso', label: 'Código acceso' },
        { name: 'activo', label: 'Activo', type: 'checkbox', defaultValue: true },
        { name: 'observaciones', label: 'Observaciones', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="-created_at"
      searchPlaceholder="Buscar por PPU, parcela o marca"
    />
  );
}
